"""
MKT Christ Commentary — Exodus chapters 7–9
Run: python3 scripts/zc-christ-exodus-7-9.py

Ch 7: Moses/Aaron before Pharaoh — staff → serpent (Aaron's swallows magicians');
      first plague: Nile to blood.
Ch 8: Frogs (2nd plague), gnats — 'finger of God' (3rd), flies with Israel/Egypt
      distinction (4th).
Ch 9: Livestock disease (5th), boils (6th), hail mixed with fire (7th).

Key Christological frames:
- Moses as mediator-type: speaks YHWH's words to the ruler of this age; Christ is the
  true Mediator who confronts the ruler of this world (John 12:31).
- The plagues as judgment against Egypt's gods (Exod 12:12; Num 33:4) — type of
  Christ's cross defeating the principalities (Col 2:15).
- Aaron's rod swallowing the serpents = the seed crushing the serpent (Gen 3:15).
- 'Finger of God' (8:19) quoted by Pharaoh's magicians → Jesus casts out demons by the
  'finger of God' / 'Spirit of God' (Luke 11:20; Matt 12:28).
- Goshen distinction in plagues 4-7 = the 'in Christ' protection from eschatological
  wrath (1 Thess 5:9; Rev 7:3).
- Hail + fire = eschatological judgment language (Rev 8:7).
- Pharaoh's hardened heart = the intractability that only the new covenant can cure
  (Ezek 36:26; 2 Cor 3:14-16).
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
  "7": {
    "1": "<p>YHWH makes Moses '<i>elohim</i> to Pharaoh' — a god-like figure before the earthly ruler. The word <i>elohim</i> here assigns Moses a divine representative role: he speaks for YHWH to the ruler of the most powerful empire on earth. This prefigures Christ's role as the definitive Word of God confronting the 'ruler of this world' (John 12:31). As Moses is YHWH's <i>elohim</i>-figure to Pharaoh, so Christ is 'the image of the invisible God' (Col 1:15) who confronts and defeats every power that claims sovereignty over humanity.</p>",
    "2": "<p>Moses speaks everything YHWH commands; Aaron speaks to Pharaoh. The mediatorial chain — YHWH → Moses → Aaron → Pharaoh — anticipates the NT pattern where the divine word passes through the Son to the world. Jesus is both Moses and Aaron in one: he is both the one who receives the Father's word perfectly (John 8:28) and the one who speaks it directly to the world without an intermediary. The doubled mediation of the exodus gives way to the single perfect Mediator (1 Tim 2:5).</p>",
    "3": "<p>'I will harden Pharaoh's heart (<i>ani aksheh et-lev par'oh</i>).' The divine hardening is already announced before the plague sequence begins. Theologically, this anticipates Paul's treatment of divine sovereignty and human responsibility in Rom 9:17–18, where he quotes Exod 9:16 and cites Pharaoh as the paradigmatic case of divine governance over the obstinate. The hardened heart is the condition of those who resist the word of God persistently — a condition that only Christ's new-covenant work reverses (Ezek 36:26; 2 Cor 3:14–16).</p>",
    "4": "<p>'Egypt will not listen to you' — the refusal of the word is announced in advance. This matches the Johannine prologue pattern: 'He came to his own and his own people did not receive him' (John 1:11). Jesus taught in parables partially because of the same dynamic — the word spoken to a hardened audience increases their accountability without converting them (Matt 13:13–15, quoting Isa 6). The exodus refuses and the ministry refuses are structurally parallel: a nation's rejection of YHWH's messenger leads to judgment.</p>",
    "5": "<p>'The Egyptians shall know that I am YHWH when I stretch out my hand over Egypt.' The goal of the plagues is revelatory — YHWH's identity as sovereign Lord is to be known through the judgment. This knowledge-through-judgment formula anticipates the cross: it was through the seeming defeat of crucifixion that 'all peoples' would be drawn to acknowledge the crucified one (John 12:32; Phil 2:9–11). Both at the Red Sea and at Golgotha, YHWH's identity as Lord is revealed precisely in the act of confronting and defeating the powers.</p>",
    "6": "<p>Moses and Aaron did as YHWH commanded — exactly. The obedience formula <i>ka'asher tzivah YHWH</i> is unqualified. This complete covenant obedience mirrors Christ's perfect obedience to the Father: 'I always do the things that are pleasing to him' (John 8:29). The exodus mediators' obedience is a type of the one who was 'obedient to the point of death' (Phil 2:8) and through whose obedience 'many will be made righteous' (Rom 5:19).</p>",
    "7": "<p>Moses was eighty, Aaron eighty-three when they spoke to Pharaoh. The age detail grounds the narrative historically but also points forward: the deliverer came not in the vigor of youth but in the fullness of time and preparation. The NT analogue is not age-literal but pattern-significant: Christ came 'when the fullness of time had come' (Gal 4:4) — the timing of both deliverers was entirely determined by YHWH, not by the deliverers themselves.</p>",
    "8": "<p>YHWH speaks to Moses and Aaron: when Pharaoh asks for a sign, Aaron is to throw his staff down. The invitation to demonstrate divine power sets up the first confrontation between YHWH's representatives and the court magicians. This is the paradigm of every encounter between the word of God and the wisdom of the world — the world demands signs (1 Cor 1:22), and YHWH provides a demonstration that cannot ultimately be matched.</p>",
    "9": "<p>Aaron throws down his staff and it becomes a <i>tanin</i> — a serpent/sea-monster. The same word is used in Gen 1:21 for the great sea creatures and in Ezek 29:3 for Pharaoh himself as 'the great dragon lying in the Nile.' The staff-serpent confrontation is cosmic: YHWH's rod becomes the creature that Pharaoh embodies. The one who would crush the serpent (Gen 3:15) acts first through a sign that makes the serpent serve YHWH's purpose.</p>",
    "10": "<p>Aaron throws his staff before Pharaoh and his servants and it becomes a serpent — the sign performed publicly, before the highest court. The public context matters: the defeat of the serpent will not happen in private. Both the plagues and the cross are public acts — YHWH's power displayed before witnesses. 'He disarmed the rulers and authorities and put them to open shame, by triumphing over them in him' (Col 2:15). The open display of power over the serpent begins here.</p>",
    "11": "<p>Pharaoh's wise men and sorcerers (<i>chakhamim, mekashefim</i>) replicate the sign with their secret arts. The magicians can produce serpents too — false signs that superficially match YHWH's. This is the NT's persistent warning about counterfeit signs: 'False christs and false prophets will arise and perform great signs and wonders, so as to lead astray, if possible, even the elect' (Matt 24:24). The ability to perform signs is not in itself proof of divine authorization.</p>",
    "12": "<p>Aaron's staff swallowed (<i>vayivla</i>) all the magicians' staffs. The decisive sign: YHWH's serpent consumes the imitations. This is the first act of the plague sequence but theologically the most important: the enemy's power is not denied but absorbed and overcome. The cross follows the same logic — death is swallowed up in victory (1 Cor 15:54, quoting Isa 25:8). The enemy's best weapon (the serpent, death) is swallowed by the one it tried to destroy.</p>",
    "13": "<p>Pharaoh's heart was hardened and he did not listen. The first hardening confirms the pattern established in v. 3. The cumulative effect of Pharaoh's refusals forms a theological argument: persistent rejection of YHWH's word hardens the heart further with each refusal. Paul uses this same logic when he describes those who suppress the truth (Rom 1:21–28) — each rejection intensifies the blindness it produces.</p>",
    "14": "<p>YHWH tells Moses: 'Pharaoh's heart is heavy (<i>kaved</i>) — he refuses to let the people go.' The <i>kaved</i> (heavy/hardened) heart of Pharaoh and the <i>kavod</i> (glory/heaviness) of YHWH share the same root — the display of YHWH's glory is directly linked to overcoming the human heart's heaviness. What glorifies YHWH most is the deliverance of people from the condition that has made them spiritually heavy and unresponsive.</p>",
    "15": "<p>YHWH instructs Moses to go to Pharaoh at the Nile in the morning — the Nile where Pharaoh went regularly. Pharaoh worshipped the Nile or monitored it as a divine resource; YHWH meets him at the place of his false security. This is the pattern of prophetic confrontation: the prophet meets the king at the place that represents his self-sufficiency. Christ confronts the rich young ruler at the point of his wealth (Mark 10:21), the scribes at the point of their legal expertise (Matt 22:34–40).</p>",
    "16": "<p>Moses confronts Pharaoh with the covenant demand: 'Let my people go that they may serve me in the wilderness.' The liberation-for-service structure of the exodus is the pattern of redemption: deliverance is not from obligation but from wrong masters. Christ's redemption works the same way: 'You were bought with a price; do not become bondservants of men' (1 Cor 7:23); 'freed from sin, you have become slaves of righteousness' (Rom 6:18). Liberation from one lord is always liberation to another.</p>",
    "17": "<p>'By this you shall know that I am YHWH: behold, I will strike the water of the Nile with the staff in my hand and it shall be turned to blood.' The water-to-blood sign is the first of the ten plagues. Blood in Hebrew thought marks both life (Lev 17:11 — 'the life of the flesh is in the blood') and death (murder, sacrifice, judgment). Turning the Nile to blood transforms Egypt's life-source into a death-marker. The Nile — Egypt's economic and religious foundation — is the first target of judgment.</p>",
    "18": "<p>The fish will die, the river stink, and Egypt will be unable to drink. The death of the fish strikes at Egypt's food economy; the stench marks the Nile as unclean; the inability to drink creates an existential crisis. The plague targets the whole person — sustenance, senses, survival — as divine judgment always does. The cross addresses the same totality: Christ 'bore our sins in his body' (1 Pet 2:24), becoming the comprehensive answer to comprehensive human need.</p>",
    "19": "<p>The command extends to all of Egypt's water — rivers, canals, ponds, pools, vessels of wood and stone. The totality of the plague is significant: every water source in Egypt, not just the Nile, turns to blood. No Egyptian could find water untouched by the judgment. This comprehensiveness prefigures the scope of Christ's work: his death and resurrection addressed not a subset of human brokenness but the total consequence of sin across every dimension of creation (Col 1:20 — 'reconciling to himself all things, whether on earth or in heaven').</p>",
    "20": "<p>Moses and Aaron do as YHWH commanded — Aaron strikes the Nile with the staff, and all the water becomes blood throughout Egypt. The execution matches the command exactly. The obedience of the mediators in performing the sign is complete, as is the scope of the judgment. This is the covenant-obedience pattern that culminates in Christ's cross: 'he became obedient to the point of death, even death on a cross' (Phil 2:8) — the supreme mediation performed with complete fidelity.</p>",
    "21": "<p>The fish died, the river stank, and Egypt could not drink. Three consequences, three dimensions of judgment: ecological death, sensory revulsion, physical suffering. The plague is not punishment for its own sake but a structured demonstration of what Egypt's gods could not do — they could not prevent YHWH from turning their most sacred resource against them. The Lord of all creation exercises his authority over the creation-elements that Egypt's religion had deified.</p>",
    "22": "<p>The Egyptian magicians did the same with their secret arts — duplicating the blood sign. But this is judgment stacked upon judgment: the magicians can turn more water to blood but cannot reverse what is already done. Their 'power' only deepens Egypt's crisis. The false prophets of the last days similarly multiply signs without healing anything; the counterfeit always intensifies the problem it pretends to solve.</p>",
    "23": "<p>Pharaoh turned and went home — his heart was hardened, he did not take even this to heart. 'Did not take it to heart' (<i>lo shat libbo*</i>) is the phrase of spiritual indifference: the sign was witnessed but not internalized. This is the parable of the sower condition (Luke 8:12) — the word heard but not absorbed. Pharaoh is the paradigm of those who see the signs of divine power and remain unmoved because the heart has grown callous (Matt 13:15).</p>",
    "24": "<p>All Egypt dug around the Nile for drinking water — the plague created a national emergency. The desperation of digging beside a polluted river for filtration water depicts the human condition under judgment: improvising survival within a broken order rather than turning to the one who can restore it. The NT equivalent is the religious improvisation of those who work the law for righteousness (Rom 10:3) when the source of life is already available in Christ.</p>",
    "25": "<p>Seven days passed after YHWH struck the Nile. The seven-day duration of the first plague grounds it in the creation-week framework — one complete cycle of time under the blood-judgment. The seven days also establish a rhythm of warning and persistence: YHWH does not strike once and immediately destroy; there is a sustained period of consequence that allows for repentance. This is the NT principle of divine patience — 'not wishing that any should perish, but that all should reach repentance' (2 Pet 3:9).</p>"
  },
  "8": {
    "1": "<p>YHWH's command to Moses for the second plague (frogs): 'Go to Pharaoh and say to him.' The repeated messenger-formula structures the plague sequence as a series of covenant lawsuits — YHWH states the case, makes the demand, announces the consequence. Each plague is a divine speech-act followed by divine action. This covenant-lawsuit structure anticipates the NT pattern of the gospel call: announcement, demand (repentance/faith), and consequence for refusal.</p>",
    "2": "<p>'If you refuse to let them go, behold I will plague all your territory with frogs.' The frog plague targets the Nile again — Egypt's sacred river will now produce not fish or crocodiles but frogs in overwhelming numbers. The frog (<i>tzfardea</i>) was associated with the Egyptian goddess Heqet (frog-headed fertility goddess). YHWH turns Egypt's symbol of fertility and regeneration into an instrument of revulsion — the same reversal pattern as the Nile blood: what was life-giving becomes suffocating.</p>",
    "3": "<p>Frogs will come into Pharaoh's house, his bedroom, his bed — into the most intimate private spaces. The plague does not stay at the river but penetrates the most personal space of the king. Divine judgment is like this: it does not respect the boundary between public and private. Christ's coming judgment will similarly expose what is hidden — 'God will judge the secrets of men by Christ Jesus' (Rom 2:16). Nothing is off-limits to the scrutiny of the Creator who made the intimate as much as the public.</p>",
    "4": "<p>Frogs into the houses of servants, people, ovens, kneading bowls — the contamination extends from the palace to the kitchen, from the royal to the domestic. The frog plague did not discriminate socially: palace and peasant were equally invaded. This equality before divine judgment anticipates what Paul states about the cross: there is no distinction — 'all have sinned and fall short of the glory of God' (Rom 3:23). Judgment is comprehensively democratic before salvation becomes comprehensively available.</p>",
    "5": "<p>Aaron stretches out his hand with his staff over Egypt's waters — rivers, canals, ponds — and frogs come out to cover Egypt. The staff as the mediator's instrument of divine power connects all the plague signs into a unified sequence. The same staff that turned the Nile to blood now summons frogs. The instrument of Moses/Aaron is the embodied extension of YHWH's word — like the cross, which is the instrument by which divine judgment and divine mercy are both extended toward the world.</p>",
    "6": "<p>Aaron stretches out his hand and frogs cover the land. The plague achieves its full extent — every surface, every space. The comprehensiveness is part of the sign's argument: no space in Egypt is outside YHWH's jurisdiction. The NT makes the same claim about Christ's lordship: 'He who descended is the one who also ascended far above all the heavens, that he might fill all things' (Eph 4:10). The plague fills Egypt to demonstrate YHWH's reach; the ascended Christ fills all things to demonstrate his lordship.</p>",
    "7": "<p>The magicians replicate the frog plague with their secret arts — more frogs appear. Again, the magicians intensify the judgment rather than alleviating it; they can add to the plague but cannot remove it. The great irony deepens: Egypt's own religious practitioners are making the situation worse. The religious systems that humans construct apart from YHWH tend toward this same irony — they multiply the burdens of law and ritual but cannot remove the fundamental problem of guilt before God (Heb 10:4).</p>",
    "8": "<p>Pharaoh calls Moses and Aaron: 'Pray to YHWH to take away the frogs — and I will let the people go to sacrifice.' This is the first instance of Pharaoh appearing to yield — the first use of prayer-language (<i>hatiru</i>) directed toward YHWH by the enemy. The reversal: the one who would not bow to YHWH's word now asks Moses to intercede. This foreshadows the eschatological acknowledgment when 'every knee will bow' (Phil 2:10–11) — including those who resisted. The intercessor is always needed when judgment falls.</p>",
    "9": "<p>Moses offers Pharaoh the choice of timing: 'When shall I pray for you, your servants, and your people?' Moses does not assume the time — he gives Pharaoh the opportunity to name the hour of relief. This gesture of deference is remarkable: the mediator offers the offender the choice of timing. Christ's intercession similarly leaves room for the sinner to call on him: 'Everyone who calls on the name of the Lord will be saved' (Rom 10:13). The intercessor is available; the timing of the call is left to the one who needs deliverance.</p>",
    "10": "<p>Pharaoh says 'Tomorrow.' Moses: 'As you say — so that you may know there is no one like YHWH our God.' The frog plague will continue through the night before relief comes, so that the removal will be unmistakably supernatural. The purpose of the delay is knowledge: YHWH's incomparability (<i>ein kaYHWH Eloheinu</i>) will be demonstrated by the precision of the answer. The NT equivalent is the resurrection's timing — 'on the third day' (1 Cor 15:4) is not accidental but scheduled, so that the deliverance from death would be unmistakably divine.</p>",
    "11": "<p>The frogs will depart from the palace and its inhabitants and from the fields — and rest only in the Nile. Complete removal to a single location: judgment fully lifted from the land, confined to the river. The removal is as comprehensive as the plague. This is the pattern of final eschatological restoration: 'He will wipe away every tear from their eyes, and death shall be no more, neither shall there be mourning, nor crying, nor pain anymore' (Rev 21:4) — the reversal of plague is total, not partial.</p>",
    "12": "<p>Moses cries out (<i>vayitzak</i>) to YHWH concerning the frogs. The intercessory cry — the same root as Israel's cry in Egypt (Exod 2:23) — is Moses performing for Egypt the very act that Israel performed for Israel. The deliverer intercedes for those he is delivering and even for those resisting deliverance. Christ's intercession on the cross ('Father, forgive them,' Luke 23:34) follows this same pattern: the mediator prays for those who have not yet turned, not only for his own people.</p>",
    "13": "<p>YHWH does according to Moses's word — the frogs die. Moses's prayer was effectual: YHWH acted 'according to the word of Moses' (<i>kidvar Moshe</i>). The intercessor's word before YHWH has operative force. This is the NT's theology of prayer through the mediator: Christ's intercession at the Father's right hand is always effectual (Heb 7:25 — 'he always lives to make intercession for them'). The frogs dying at Moses's word is a type of the authority of Christ's intercessory prayer.</p>",
    "14": "<p>The frogs were gathered into heaps (<i>chamarim chamarim</i>) — the land stank. Death followed deliverance: the removal of the plague left its residue in rotting heaps across Egypt. The smell of death lingered after the judgment was lifted. This is the sobriety of divine discipline: its aftermath is not immediately pleasant. Paul uses the same note in 2 Cor 7:10 — 'godly grief produces a repentance that leads to salvation without regret.' The heaps of dead frogs are the grief that follows the moment of relief.</p>",
    "15": "<p>When Pharaoh saw there was relief (<i>hakhafah*</i>) he hardened his heart and would not listen. The classic post-relief relapse: the crisis passed, the urgency dissolved, the promise forgotten. This pattern — relief producing fresh hardness — is the most tragic form of spiritual regression. The letter to the Hebrews warns against the same dynamic: 'See to it that no one falls short of the grace of God' (Heb 12:15), not by remaining in crisis but by failing to keep the lesson of crisis past.</p>",
    "16": "<p>YHWH tells Moses: 'Say to Aaron, stretch out your staff and strike the dust of the earth so it becomes gnats throughout Egypt.' The third plague (gnats/lice, <i>kinnim</i>) requires no warning to Pharaoh — it comes without negotiation. The pattern shifts: the first two plagues were announced in advance; the third comes unannounced. This escalation signals that the window for pre-warning mercy has closed for this plague cycle. Divine patience has its own structure: there are moments when judgment follows without further announcement.</p>",
    "17": "<p>Aaron stretches out the staff and strikes the dust — dust becomes gnats on humans and animals throughout Egypt. The gnats come from the dust (<i>afar</i>) — the same substance from which humanity was formed (Gen 2:7) and to which judgment returns it ('dust you are, and to dust you shall return,' Gen 3:19). YHWH uses the humblest material — dust — to produce one of the most pervasive plagues. The cross similarly works through what the world considers base: 'We preach Christ crucified, a stumbling block to Jews and folly to Gentiles' (1 Cor 1:23), yet this foolishness is the wisdom and power of God.</p>",
    "18": "<p>The magicians tried to replicate the gnats with their secret arts — and failed. They could not. This is the first failure of the magicians. Water-to-blood and frogs they could match; gnats from dust they could not. The boundary of counterfeit power has been reached: the imitation can go so far and no further. There is a point where false spiritual power is exposed as impotent — where the pretense of alternative authority simply fails. The cross is that point in ultimate terms: death could not hold the one who is Life (Acts 2:24).</p>",
    "19": "<p>'This is the finger of God (<i>etzba Elohim</i>),' the magicians said to Pharaoh. The magicians' own confession: they recognize divine power at the point of their failure. <i>Etzba Elohim</i> — finger of God — will appear again in 31:18 as the inscription-method of the Sinai tablets. Luke 11:20 has Jesus say he casts out demons 'by the finger of God'; Matthew 12:28 renders this 'by the Spirit of God.' The Spirit who empowers Jesus's exorcisms is the same divine 'finger' the magicians encountered at their limit — the power that no counterfeit can imitate.</p>",
    "20": "<p>Pharaoh's heart was hardened and he did not listen — as YHWH had said. The refrain returns. The compounding of the phrase 'as YHWH had said' (<i>ka'asher diber YHWH</i>) is theologically precise: Pharaoh's hardening is not a surprise or a divine failure; it was announced in advance (4:21; 7:3). The sovereignty of YHWH over Pharaoh's resistance becomes the vehicle through which YHWH's name is proclaimed throughout the earth (Rom 9:17). The resistance serves the revelation.</p>",
    "21": "<p>YHWH tells Moses: 'Rise early in the morning and stand before Pharaoh.' The fourth plague (flies) begins with YHWH taking the initiative — going to Pharaoh at his morning routine. The divine confrontation is persistent and patterned. The gospel's persistent announcement to a hostile world follows the same structure: 'Preach the word; be ready in season and out of season' (2 Tim 4:2). The word of God is not deterred by prior refusals.</p>",
    "22": "<p>YHWH will set apart (<i>hifleiti</i>) the land of Goshen where Israel dwells — no swarms there. This is the first explicit distinction between Israel and Egypt in the plague sequence. From the fourth plague onward, YHWH places a boundary around his people that the judgment cannot cross. This separation is the OT form of what Paul calls being 'in Christ' — those joined to the covenant people are shielded from the wrath that falls on the world. 'God has not destined us for wrath, but to obtain salvation through our Lord Jesus Christ' (1 Thess 5:9).</p>",
    "23": "<p>'I will put a division (<i>pedut</i>) between my people and your people.' <i>Pedut</i> means separation/redemption — the same root as <i>pidyon</i> (ransom/redemption). The division between Israel and Egypt is itself an act of redemption: to be set apart from judgment is to be ransomed from it. Christ's work creates the same redemptive division: those in him are set apart from condemnation. 'There is therefore now no condemnation for those who are in Christ Jesus' (Rom 8:1). The fourth plague's Goshen-distinction is the covenant type of this.</p>",
    "24": "<p>Heavy swarms of flies came into Pharaoh's house and the houses of his servants and throughout Egypt. But Goshen was spared. The contrast is enacted: the spatial boundary between judgment and protection is visible on the land. Two adjacent communities, one under plague and one untouched. The visibility of the distinction was itself part of the sign — it was not that Goshen escaped by chance but that YHWH specifically exempted it. The protection of God's people in the midst of judgment is always a visible testimony to his covenant faithfulness.</p>",
    "25": "<p>Pharaoh calls Moses and Aaron: 'Go, sacrifice to your God in the land.' The first concession — but it is a half-concession: sacrifice within Egypt, not a three-day journey into the wilderness. Pharaoh is willing to accommodate religion that stays within his territorial control. This is the perennial temptation for the church: to accept a form of Christianity that stays within the world's boundaries, that does not go out from Egypt into the wilderness of cross-bearing. Jesus refused the same compromise: 'My kingdom is not of this world' (John 18:36).</p>",
    "26": "<p>Moses refuses: what Israel must sacrifice would be 'an abomination to the Egyptians' — they would stone us. The sacrifices required by YHWH are offensive to Egypt's religion. This maps onto the NT offense of the cross: 'the word of the cross is folly to those who are perishing' (1 Cor 1:18). The sacrifice YHWH requires — the death of his Son — is precisely what is most offensive to human religious expectation. It cannot be reduced to something the world will accept; it must go into the wilderness, outside the camp (Heb 13:13).</p>",
    "27": "<p>'We must go three days' journey into the wilderness and sacrifice to YHWH our God as he commands us.' The three-day journey has long attracted theological attention — a journey into the wilderness that ends in sacrifice, followed by return. This three-day structure resonates with the resurrection: Jesus's journey into death (the wilderness of divine absence) for three days ends in the sacrifice completed and the return in resurrection. The pattern is embedded in the exodus demand before it is fulfilled in the cross.</p>",
    "28": "<p>Pharaoh says: 'I will let you go to sacrifice — only do not go very far away. Pray for me.' Another half-concession: you may go, but not far, and pray for me while you go. Pharaoh wants the benefits of Moses's intercession (relief from plagues) while maintaining control over the distance of Israel's departure. This is the condition of every half-hearted response to the gospel: seeking the benefits of Christ (comfort, forgiveness) while refusing the cost of full surrender (leaving Egypt, dying to self).</p>",
    "29": "<p>Moses promises to pray for the flies to depart — and warns Pharaoh not to deceive again in preventing Israel from going. The intercessor's prayer is conditional on the king's follow-through. Moses has been deceived before (implied) and names the risk explicitly. This is pastoral realism: intercessory prayer operates within the moral seriousness of covenant relationship. Intercession is not manipulation of God but honest engagement between the mediator, the petitioner, and YHWH.</p>",
    "30": "<p>Moses went out from Pharaoh and prayed to YHWH. The prayer follows the commitment — Moses does not wait to see if Pharaoh will follow through before interceding. Intercession precedes the evidence of the petitioner's response. This reflects Christ's intercession: he prays for us while we are still sinners (Rom 5:8), not after we have proven ourselves. The mediator acts first in faith that YHWH will respond and that the prayer will produce results in the one prayed for.</p>",
    "31": "<p>YHWH did according to Moses's word — the flies left, not one remained. The effectual prayer principle: YHWH acts 'according to the word of Moses,' just as in the frog plague (v. 13). The intercessor's word has force because YHWH honors the covenant relationship with his mediator. Christ's intercessory prayer is similarly effectual — 'I know that you always hear me' (John 11:42) — not because of the mediator's merit but because of the covenant relationship YHWH establishes with his anointed.</p>",
    "32": "<p>Pharaoh hardened his heart even this time — he did not let the people go. The cycle completes: plague, prayer, relief, and then renewed hardness. The relief given did not produce gratitude or change. This is the intractability of the unregenerate heart before divine grace: it can receive mercy, be briefly moved, and then return to its former position. The new covenant addresses this at the root: 'I will give you a new heart, and a new spirit I will put within you' (Ezek 36:26). Without heart-transformation, external relief produces only temporary compliance.</p>"
  },
  "9": {
    "1": "<p>The fifth plague: YHWH's messenger-formula to Pharaoh through Moses — 'Let my people go that they may serve me.' The sixth repetition of the deliverance demand. The persistent repetition is not rhetorical failure but covenant documentation — YHWH offers the opportunity for response with every announcement. The gospel similarly does not tire of its own proclamation: 'How then will they call on him in whom they have not believed? And how are they to believe in him of whom they have never heard?' (Rom 10:14). The repeated announcement is itself the grace.</p>",
    "2": "<p>'If you refuse to let them go and hold onto them' — the conditional for the fifth plague. The two verbs (<i>me'en leshallach</i> and <i>machaziq bahem</i>) describe both passive refusal and active grasping — Pharaoh both refuses to release and grips them tighter. This double resistance (refusing and gripping) describes the condition of every enslaved will: it does not merely fail to come to freedom but actively clings to bondage. Christ's deliverance addresses both the external captors and the internal resistance.</p>",
    "3": "<p>YHWH's hand will be on Egypt's livestock — horses, donkeys, camels, herds, flocks. The fifth plague targets the economic infrastructure of Egypt: its transportation, its agriculture, its food supply, its trade goods. The targeting is systematic — every category of working and food animal. This comprehensive economic judgment mirrors the NT's teaching that creation itself groans under sin's effects (Rom 8:20–22): every dimension of the creaturely economy is subject to the consequences of human rebellion.</p>",
    "4": "<p>YHWH will distinguish (<i>hifla YHWH</i>) between Israel's livestock and Egypt's livestock — not one of Israel's shall die. The Goshen-distinction extends to Israel's animals: the covenant protection is not only for persons but for the whole household, the whole economy of the covenant people. The NT analogue is the blessing that flows to those connected to the covenant people: 'The unbelieving husband is made holy because of his wife' (1 Cor 7:14). Covenant protection has a household radius.</p>",
    "5": "<p>YHWH set a time: 'Tomorrow YHWH will do this thing in the land.' The advance notice with a specific time-stamp is unprecedented in the plague sequence. By announcing the precise timing, YHWH increases Pharaoh's accountability while providing one more opportunity for response. The prophetic announcement of judgment with specific timing (Jonah 3:4 — 'in forty days Nineveh will be overthrown') is always also an implicit call to preemptive repentance. The deadline intensifies the mercy of the warning.</p>",
    "6": "<p>YHWH did that thing the next day: all Egypt's livestock died; not one of Israel's died. The contrast is starkly enacted: 'all the livestock of Egypt died' and 'not one of the livestock of Israel died' — the two outcomes sit in the same verse. The juxtaposition of total loss and total preservation is the plague narrative's most concentrated expression of the judgment/salvation binary. This binary runs from here through the Passover (death/protection) and ultimately to the cross (death for sin, life for the forgiven).</p>",
    "7": "<p>Pharaoh sent and found that not one of Israel's livestock had died — and his heart was hardened. The investigation confirmed the miracle; the hardening followed the confirmation. This is the most counterintuitive moment in the plague sequence: Pharaoh verifies the supernatural protection of Israel and becomes more resistant. Confirming miracles do not automatically produce faith when the heart is set against the messenger. Jesus experienced the same pattern: 'Though he had done so many signs before them, they still did not believe in him' (John 12:37).</p>",
    "8": "<p>YHWH tells Moses and Aaron: 'Take handfuls of soot (<i>pigam kivshanim*</i>) from the kiln and let Moses throw it toward the sky.' The sixth plague (boils) is generated from the kiln — the same kilns where Israel labored under Egyptian oppression (the brick-making kilns of Exod 1:14; 5:7–19). The instrument of Israel's suffering becomes the source of Egypt's judgment. The suffering that the oppressor inflicted is now turned against the oppressor — a pattern that reaches its ultimate expression in the cross: the death that sin brought into the world becomes the means of sin's defeat.</p>",
    "9": "<p>The soot becomes fine dust over Egypt and causes boils on humans and animals. Boils (<i>shchin</i>) — painful, festering skin eruptions — afflict both people and animals. The body itself becomes the site of judgment: the skin that defines the boundary between self and world breaks down. Boils in the Hebrew law-code are one of the covenant curse conditions (Deut 28:35 — 'YHWH will strike you with the boils of Egypt'). The sixth plague is not merely a natural disaster but a covenant curse enacted on the oppressor nation.</p>",
    "10": "<p>Moses throws the soot upward, and boils break out on humans and animals throughout Egypt. The upward gesture is significant: the soot lifted toward heaven and falling across Egypt enacts the principle that judgment comes from above. In the NT, both blessing and judgment descend from YHWH — the same divine sovereignty that sends the rain of grace also sends the fire of judgment (Matt 5:45; Rev 8:5). The throwing-upward of the soot is a physical enactment of prayer-and-answer: Moses sends it up; YHWH sends it back as plague.</p>",
    "11": "<p>The magicians could not stand before Moses because of the boils — the boils were on them too. The magicians are now afflicted by the same plague they could no longer counter: their own bodies are under the judgment. The counterfeit religious system has been rendered physically incapable of functioning — its practitioners cannot serve in the presence of the one they opposed. The final judgment will work similarly: every pretender to divine authority will be silenced by their own inability to withstand the holy presence (Rev 6:15–17 — kings, generals, everyone hiding from 'the face of him who is seated on the throne').</p>",
    "12": "<p>YHWH hardened Pharaoh's heart — this time the hardening is explicitly attributed to YHWH, not merely described as Pharaoh's own doing. The transition from Pharaoh hardening his own heart (7:13, 22; 8:15, 19, 32) to YHWH hardening it (9:12; 10:1, 20, 27) marks the theological shift Paul discusses in Rom 9:18 — at some point, the one who hardens himself is 'given over' to the hardening he chose. The divine hardening is not arbitrary but is the confirmed establishment of the choice Pharaoh has been making all along.</p>",
    "13": "<p>YHWH tells Moses: 'Rise early, stand before Pharaoh, and say: Let my people go that they may serve me.' The messenger-formula continues unchanged despite escalating hardness and escalating plagues. YHWH's word does not adapt to Pharaoh's resistance; the demand remains constant. The unchanging demand mirrors the gospel's unchanging content: 'Jesus Christ is the same yesterday and today and forever' (Heb 13:8). What YHWH requires of Pharaoh — full surrender of Israel — is not negotiable and does not change.</p>",
    "14": "<p>YHWH will send all his plagues against Pharaoh's heart and servants and people — 'so that you may know there is no one like me in all the earth.' The knowledge-goal is reiterated with intensification: not just Egypt will know, but all the earth. This universal scope matches the NT's universal proclamation goal. The plagues that demonstrate YHWH's incomparability in Egypt become the precedent for the cross that demonstrates YHWH's love 'in all the earth' — 'if I am lifted up from the earth, I will draw all people to myself' (John 12:32).</p>",
    "15": "<p>'For by now I could have stretched out my hand and struck you and your people with pestilence and you would have been cut off from the earth.' YHWH's restraint is explicit: the plagues up to this point are not maximum judgment but measured judgment. YHWH could have destroyed Egypt entirely at any point; the prolonged plague sequence is itself an act of mercy — discipline toward potential repentance. Peter identifies the same principle in God's apparent delay of judgment: 'The Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish' (2 Pet 3:9).</p>",
    "16": "<p>'But for this purpose I raised you up — to show you my power, so that my name may be proclaimed in all the earth.' This verse is quoted by Paul in Rom 9:17 as the paradigmatic statement of divine sovereignty over history. YHWH raised up Pharaoh (<i>he'emadticha*</i>) — brought him to this position — not for his own benefit but as the instrument through which YHWH's power would be demonstrated and his name proclaimed. Pharaoh's resistance serves YHWH's revelation. The cross operates by the same principle: the ultimate act of human resistance to God (crucifying the Son) becomes the ultimate declaration of God's name and power to the world.</p>",
    "17": "<p>'You are still exalting yourself against my people by not letting them go.' The verb <i>mistalea</i> (exalt yourself against) captures Pharaoh's posture: self-elevation at the expense of YHWH's people. This is the posture of all oppressive power and of the devil himself ('I will make myself like the Most High,' Isa 14:14). Christ's incarnation is the direct inversion of this: 'though he was in the form of God, he did not count equality with God a thing to be grasped, but emptied himself' (Phil 2:6–7). The self-exalter is humbled; the self-emptier is exalted.</p>",
    "18": "<p>'Tomorrow I will cause very heavy hail to fall — such as has never been in Egypt since its founding until now.' The seventh plague is announced as unprecedented: the superlative judgment language signals that escalation is approaching its peak. The phrase 'such as has never been' will recur in the plague climax language and in eschatological texts (Dan 12:1 — 'a time of trouble such as has never been'; Matt 24:21 — 'great tribulation, such as has not been from the beginning of the world'). The plagues establish a literary-theological template for describing final judgment.</p>",
    "19": "<p>'Now therefore send, bring your livestock and everything you have in the field to shelter — every human being and animal in the field that is not brought home will die when the hail falls on them.' The pre-plague warning contains a salvation offer: those who take cover will survive. YHWH warns before he strikes and provides a way of escape within the warning. This is the pattern of all covenant grace — judgment announced, a way of escape opened, human response determining outcome. Noah and the ark, Rahab's scarlet cord, Passover blood — all are the same pattern of provided protection within announced judgment.</p>",
    "20": "<p>Those among Pharaoh's servants who feared the word of YHWH (<i>hayare et-dvar YHWH</i>) — they brought their servants and livestock indoors. Even within Egypt, some responded to YHWH's warning with protective action. The 'fear of YHWH' within Egypt is remarkable: YHWH's words produced faith-response in some Egyptians during the plagues. The mixed response within Egypt prefigures the mixed response to the gospel within every nation — 'from every tribe and language and people and nation' (Rev 5:9), there will be those who hear and respond.</p>",
    "21": "<p>Those who did not set their hearts on the word of YHWH left their servants and livestock in the field. The two responses divide Egypt along the line of the word: those who took it to heart and those who disregarded it. The word itself is the dividing line — this is what Jesus means when he says 'I came not to bring peace but a sword' (Matt 10:34). The gospel does not divide on ethnicity or class but on response to the word. The hail plague makes visible what is true in every generation.</p>",
    "22": "<p>YHWH tells Moses: 'Stretch out your hand toward heaven so that hail may fall on the land of Egypt — on humans and animals and every plant of the field.' The gesture toward heaven for the hail mirrors the soot-throwing for boils (v. 10) but in the opposite direction: Moses reaches up rather than throwing up. The intercessory/mediatorial gesture connects earth to heaven in both directions — plague descends as Moses reaches toward the source of judgment. The mediator's posture determines the direction of the divine action.</p>",
    "23": "<p>Moses stretched out his staff toward heaven and YHWH sent thunder and hail — and fire (<i>esh*</i>) ran down to earth. YHWH thundered (<i>qolot*</i>) and fire and hail fell together. The hail-and-fire combination appears in Revelation 8:7 as the first trumpet judgment — 'hail and fire, mixed with blood, were thrown upon the earth.' The Exodus plague is the literary and theological template for Revelation's eschatological judgment imagery. The plagues of Egypt are a micro-pattern for the final plagues of history.</p>",
    "24": "<p>Hail and fire flashing in the midst of the hail — very heavy, such as had not been in Egypt since becoming a nation. The unprecedented severity is repeated: the superlative judgment language marks this as the most severe plague to date. The fire (lightning) within the hail reversed the normal order of nature — fire and water do not coexist. The miracle is in the combination: divine judgment operates outside natural categories. The cross similarly defies categories — the Son of God dying is not a natural event but a cosmic anomaly that splits the veil between earth and heaven (Matt 27:51).</p>",
    "25": "<p>The hail struck every plant of the field and every tree in the field throughout Egypt — everything in the open, human and animal. The ecological scope: vegetation, trees, animals, people — everything in the open was struck. The reversal of the creation order that began with the Nile (water corrupted) now reaches the vegetation and animal world. The plague sequence is a systematic uncreation — reversing the good creation of Gen 1–2 domain by domain. Christ's redemption is a systematic recreation of the same domains (2 Cor 5:17; Rom 8:21).</p>",
    "26": "<p>Only in the land of Goshen, where Israel lived, there was no hail. The Goshen distinction holds through the seventh plague as through the fourth, fifth, and sixth. The cumulative Goshen exemptions build the case for covenant protection as the defining mark of YHWH's people. By the time of the Passover (ch. 12), the pattern is fully established: what YHWH marks, the judgment passes over. The Passover blood is the explicit sign of what Goshen location expressed implicitly — the covenant covers those who belong to YHWH.</p>",
    "27": "<p>Pharaoh called Moses and Aaron: 'I have sinned this time. YHWH is righteous; I and my people are in the wrong.' The first explicit confession from Pharaoh — the only explicit statement of sin and of YHWH's righteousness in the entire plague narrative. The confession is real in its content but not in its depth: Pharaoh correctly identifies the categories (YHWH = righteous; we = wrong) but the confession does not penetrate to repentance. The NT distinguishes between 'worldly grief that produces death' and 'godly grief that produces repentance' (2 Cor 7:10). Pharaoh's confession is the former.</p>",
    "28": "<p>'Pray to YHWH — there has been enough of God's thunder and hail. I will let you go; you shall stay no longer.' The prayer-petition returns — Pharaoh wants intercession but not transformation. He asks Moses to pray the plague away without committing to the covenant change the prayer would signify. This is the condition of superficial religiosity: using prayer as a technique to obtain relief without pursuing the relationship with God that genuine prayer requires.</p>",
    "29": "<p>Moses says: 'As soon as I have gone out of the city I will spread out my hands to YHWH — the thunder will cease and there will be no more hail, so that you may know that the earth is YHWH's.' The purpose of the prayer's answer is stated: knowledge — 'so that you may know the earth is YHWH's' (<i>laYHWH ha'aretz*</i>). The earth belongs to YHWH (Ps 24:1). Every plague has been a demonstration of this ownership — the Creator reasserting his rights over his own creation against those who have claimed it for themselves (Pharaoh) or abandoned it to false gods (Egypt).</p>",
    "30": "<p>'But I know that you and your servants do not yet fear YHWH God.' Moses prays and then immediately issues the prophetic diagnosis: the relief will come but the fear of YHWH has not followed the confession. Moses knows Pharaoh's heart — the pattern of relief-and-relapse has established it. The prophet sees through the surface of confession to the absence of genuine transformation beneath. Christ similarly 'knew what was in man' (John 2:25) and did not trust himself to those who believed on the basis of signs alone (John 2:23–24).</p>",
    "31": "<p>The flax and barley were struck — the barley was in ear and the flax was in bud at the time of the plague. The agricultural specificity grounds the plague in seasonal reality: the hail destroyed the early spring crops (barley and flax ripen in January-March in Egypt). This is not supernatural exaggeration but historically plausible timing. The specificity of divine judgment is part of its integrity — YHWH does not deal in vague catastrophe but in precisely placed intervention that is historically verifiable.</p>",
    "32": "<p>But the wheat and spelt were not struck — they were later crops. The partial crop destruction (early crops destroyed, late crops spared) left Egypt with diminished but not eliminated food resources. YHWH calibrated the plague to maximize warning without immediate annihilation. This calibration reflects the NT principle of structured discipline: 'He disciplines us for our good, that we may share in his holiness' (Heb 12:10). The goal is not destruction but the knowledge that produces change.</p>",
    "33": "<p>Moses left Pharaoh, went out of the city, and spread out his hands to YHWH — the thunder and hail ceased, the rain stopped pouring on the earth. The prayer was answered immediately and completely. Moses spread his hands (<i>vayyifros kapav*</i>) — the bodily posture of complete openness before YHWH, lifting both hands to heaven. This gesture appears throughout Scripture as the stance of intercessory prayer (1 Kgs 8:22; Ezra 9:5) and ultimately finds its fullest expression in the crucifixion — arms spread wide, the ultimate intercessory posture.</p>",
    "34": "<p>When Pharaoh saw that the rain and hail and thunder ceased, he sinned again and hardened his heart — he and his servants. The cycle repeats with confirmation: not only Pharaoh but his servants hardened themselves. The individual hardening has become collective; the court culture has normalized resistance to YHWH's word. This community of shared hardness is the institutional form of sin — when the structures and cultures of a society are organized around the rejection of YHWH's authority, individual change becomes harder. Christ confronted the same institutional sin in the religious establishment of his day.</p>",
    "35": "<p>Pharaoh's heart was hardened — he did not let the Israelites go, as YHWH had spoken through Moses. The chapter closes on the same note as every previous cycle: hardness, non-release, fulfillment of YHWH's word. But the phrase 'as YHWH had spoken through Moses' (<i>ka'asher diber YHWH beyad-Moshe</i>) frames the refusal as confirmation rather than defeat: YHWH's word is being fulfilled even in Pharaoh's non-compliance. The intractability of the enemy does not frustrate the divine word but fulfills it — the same principle that governs the cross: 'this Jesus, delivered up according to the definite plan and foreknowledge of God, you crucified and killed by the hands of lawless men' (Acts 2:23).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'exodus')
    merge_comm(existing, EXODUS)
    save_comm('mkt-christ', 'exodus', existing)
    print('Exodus 7-9 mkt-christ written.')
    import pathlib
    out = json.loads((ROOT / 'data/commentary/mkt-christ/exodus.json').read_text())
    il = json.loads((ROOT / 'data/interlinear/exodus.json').read_text())
    all_ok = True
    for ch in range(7, 10):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present.')

if __name__ == '__main__':
    main()
